import{_ as o,C as A,o as s,c as E,a5 as t,b as l,w as a,a as r,E as i,a4 as p}from"./chunks/framework.gGRxziV4.js";const C=JSON.parse('{"title":"选型与实践","description":"","frontmatter":{},"headers":[],"relativePath":"04-多Agent架构/05-选型与实践.md","filePath":"04-多Agent架构/05-选型与实践.md","lastUpdated":1774181700000}'),g={name:"04-多Agent架构/05-选型与实践.md"};function d(c,n,h,b,u,B){const e=A("Mermaid");return s(),E("div",null,[n[2]||(n[2]=t('<h1 id="选型与实践" tabindex="-1">选型与实践 <a class="header-anchor" href="#选型与实践" aria-label="Permalink to &quot;选型与实践&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 4 模块的第 5 章。</p></blockquote><p>怎么选？从简单开始，按需演进——没有银弹，只有权衡。</p><hr><h2 id="选型框架" tabindex="-1">选型框架 <a class="header-anchor" href="#选型框架" aria-label="Permalink to &quot;选型框架&quot;">​</a></h2><p>选型没有标准答案，但有一个清晰的决策框架。</p><h3 id="架构选型四问" tabindex="-1">架构选型四问 <a class="header-anchor" href="#架构选型四问" aria-label="Permalink to &quot;架构选型四问&quot;">​</a></h3><p><strong>问题一：任务是否需要多步推理？</strong></p><ul><li>否 → 直接调用 LLM，不需要 Agent 框架</li><li>是 → 继续</li></ul><p><strong>问题二：步骤之间是否有依赖关系？</strong></p><ul><li>否 → 可以并行（Sectioning）</li><li>是 → 需要串行或条件分支（Chaining / Routing）</li></ul><p><strong>问题三：任务结构是否已知？</strong></p><ul><li>是 → 静态 Workflow（Chaining、Routing、Sectioning）</li><li>否 → 动态编排（Orchestrator-Workers）</li></ul><p><strong>问题四：输出质量是否关键？</strong></p><ul><li>否 → 单 Agent 执行</li><li>是 → 加 Evaluator-Optimizer 循环</li></ul><hr><h2 id="从简单开始" tabindex="-1">从简单开始 <a class="header-anchor" href="#从简单开始" aria-label="Permalink to &quot;从简单开始&quot;">​</a></h2><p>Anthropic 最新的 Agent 构建指南反复强调一个原则：<strong>从简单开始</strong>。</p><h3 id="三种工作流模式" tabindex="-1">三种工作流模式 <a class="header-anchor" href="#三种工作流模式" aria-label="Permalink to &quot;三种工作流模式&quot;">​</a></h3><p><strong>第一种：单 Agent 单工具调用</strong>。用户问一个问题，Agent 调用一个工具回答。最简单，覆盖 80% 的简单场景。</p><p><strong>第二种：单 Agent 多步 ReAct 循环</strong>。用户给一个目标，Agent 在思考-行动-观察循环中自主完成。覆盖大部分中等复杂度场景。</p><p><strong>第三种：多 Agent 协作</strong>。复杂任务需要多个 Agent 分工协作。只在前两种无法满足需求时才引入。</p><p>大多数团队的错误是从第三种开始——一上来就搭多 Agent 架构，结果系统复杂度远超需求，调试困难，成本高昂。</p><h3 id="演进案例" tabindex="-1">演进案例 <a class="header-anchor" href="#演进案例" aria-label="Permalink to &quot;演进案例&quot;">​</a></h3>',24)),(s(),l(p,null,{default:a(()=>[i(e,{id:"mermaid-106",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%E9%98%B6%E6%AE%B51%3A%20%E5%8D%95Agent%20%2B%20Routing%3Cbr%2F%3E80%25%E5%9C%BA%E6%99%AF%5D%20--%3E%20B%5B%E9%98%B6%E6%AE%B52%3A%20%2B%20RAG%20%E6%A3%80%E7%B4%A2%3Cbr%2F%3E%E5%9B%9E%E7%AD%94%E6%9B%B4%E5%87%86%E7%A1%AE%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%98%B6%E6%AE%B53%3A%20%2B%20ReAct%20%E5%BE%AA%E7%8E%AF%3Cbr%2F%3E%E8%87%AA%E4%B8%BB%E5%A4%9A%E6%AD%A5%E6%8E%A8%E7%90%86%5D%0A%20%20%20%20C%20--%3E%20D%5B%E9%98%B6%E6%AE%B54%3A%20%2B%20%E5%A4%9AAgent%3Cbr%2F%3ELead%20%2B%20Sub-Agents%5D%0A%20%20%20%20D%20--%3E%20E%5B%E9%98%B6%E6%AE%B55%3A%20%2B%20Evaluator-Optimizer%3Cbr%2F%3E%E8%B4%A8%E9%87%8F%E4%BF%9D%E8%AF%81%5D%0A%20%20%20%20style%20A%20fill%3A%234a9%0A%20%20%20%20style%20B%20fill%3A%236bc%0A%20%20%20%20style%20C%20fill%3A%238cf%0A%20%20%20%20style%20D%20fill%3A%23aaf%0A%20%20%20%20style%20E%20fill%3A%23f96%0A"})]),fallback:a(()=>[...n[0]||(n[0]=[r(" Loading... ",-1)])]),_:1})),n[3]||(n[3]=t('<blockquote><p>💡 <strong>图解：</strong> 每个阶段都是在前一个阶段不够用时才引入——从阶段1走到阶段5是按需演进，不是一步到位。</p></blockquote><p><strong>阶段一</strong>：客服系统，单 Agent + Routing。根据用户意图路由到不同的回答模板。成本低、可控、覆盖 80% 场景。</p><p><strong>阶段二</strong>：引入知识库。单 Agent + RAG 检索。回答更准确但流程不变。</p><p><strong>阶段三</strong>：复杂问题需要多步推理。单 Agent + ReAct 循环。Agent 自主搜索、分析、生成报告。</p><p><strong>阶段四</strong>：某些问题需要多角度研究。引入多 Agent——Lead Agent 协调，Sub-Agents 分别研究不同方面。</p><p><strong>阶段五</strong>：高价值输出需要质量保证。引入 Evaluator-Optimizer 循环。</p><p>每个阶段都是在前一个阶段无法满足需求时才引入更复杂的架构。</p><hr><h2 id="选型决策树" tabindex="-1">选型决策树 <a class="header-anchor" href="#选型决策树" aria-label="Permalink to &quot;选型决策树&quot;">​</a></h2>',9)),(s(),l(p,null,{default:a(()=>[i(e,{id:"mermaid-134",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E5%BC%80%E5%A7%8B%5D%20--%3E%20B%7B%E9%9C%80%E8%A6%81%E5%A4%9A%E6%AD%A5%E6%8E%A8%E7%90%86%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E5%90%A6%7C%20C%5B%E5%8D%95%E6%AC%A1%20LLM%20%E8%B0%83%E7%94%A8%5D%0A%20%20%20%20B%20--%3E%7C%E6%98%AF%7C%20D%7B%E4%BB%BB%E5%8A%A1%E7%BB%93%E6%9E%84%E5%B7%B2%E7%9F%A5%EF%BC%9F%7D%0A%20%20%20%20D%20--%3E%7C%E5%90%A6%7C%20E%5BOrchestrator-Workers%5D%0A%20%20%20%20D%20--%3E%7C%E6%98%AF%7C%20F%7B%E9%9C%80%E8%A6%81%E5%B9%B6%E8%A1%8C%EF%BC%9F%7D%0A%20%20%20%20F%20--%3E%7C%E6%98%AF%7C%20G%5BSectioning%5D%0A%20%20%20%20F%20--%3E%7C%E5%90%A6%7C%20H%7B%E9%9C%80%E8%A6%81%E5%88%86%E7%B1%BB%E8%B7%AF%E7%94%B1%EF%BC%9F%7D%0A%20%20%20%20H%20--%3E%7C%E6%98%AF%7C%20I%5BRouting%5D%0A%20%20%20%20H%20--%3E%7C%E5%90%A6%7C%20J%7B%E9%9C%80%E8%A6%81%E9%AB%98%E5%8F%AF%E9%9D%A0%E6%80%A7%EF%BC%9F%7D%0A%20%20%20%20J%20--%3E%7C%E6%98%AF%7C%20K%5BVoting%20%2F%20Evaluator-Optimizer%5D%0A%20%20%20%20J%20--%3E%7C%E5%90%A6%7C%20L%5BChaining%5D%0A%20%20%20%20style%20A%20fill%3A%234a9%0A%20%20%20%20style%20C%20fill%3A%23ddd%0A%20%20%20%20style%20E%20fill%3A%238cf%0A%20%20%20%20style%20G%20fill%3A%238cf%0A%20%20%20%20style%20I%20fill%3A%238cf%0A%20%20%20%20style%20K%20fill%3A%23f96%0A%20%20%20%20style%20L%20fill%3A%23ddd%0A"})]),fallback:a(()=>[...n[1]||(n[1]=[r(" Loading... ",-1)])]),_:1})),n[4]||(n[4]=t(`<blockquote><p>💡 <strong>图解：</strong> 选型从简单开始——大多数任务 Chaining 就够了，真正需要复杂架构的场景是少数。</p></blockquote><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开始</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  ├─ 需要多步推理？── 否 ──→ 单次 LLM 调用</span></span>
<span class="line"><span>  │</span></span>
<span class="line"><span>  └─ 是</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├─ 任务结构已知？── 否 ──→ Orchestrator-Workers</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      └─ 是</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          ├─ 需要并行？── 是 ──→ Sectioning</span></span>
<span class="line"><span>          │</span></span>
<span class="line"><span>          └─ 否</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              ├─ 需要分类路由？── 是 ──→ Routing</span></span>
<span class="line"><span>              │</span></span>
<span class="line"><span>              └─ 否</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  ├─ 需要高可靠性？── 是 ──→ Voting 或 Evaluator-Optimizer</span></span>
<span class="line"><span>                  │</span></span>
<span class="line"><span>                  └─ 否 ──→ Chaining</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><hr><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><p><strong>过度工程</strong>：一上来就搭多 Agent 系统，结果 80% 的功能用不上。从最简单的能工作的方案开始，按需演进。</p><p><strong>忽视成本</strong>：每个 Agent 调用都是一次 LLM 调用。多 Agent 架构的成本随 Agent 数量线性甚至超线性增长。搭架构之前先算成本。</p><p><strong>忽略失败处理</strong>：多 Agent 系统中任何一个环节失败都可能级联。必须有超时控制、重试机制、优雅降级。</p><p><strong>静态思维</strong>：需求会变，架构要能演进。不要把当前的架构当成最终形态，设计时考虑可扩展性。</p><hr><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><ol><li><strong>先让单 Agent 尽量工作</strong>，不要急着引入多 Agent</li><li><strong>按需演进</strong>，当前架构不够用时再升级</li><li><strong>成本意识</strong>，复杂架构 = 更高成本</li><li><strong>可调试性</strong>，越复杂的系统越难调试，设计时考虑可观测性</li><li><strong>从失败中学习</strong>，每次失败都是架构改进的机会</li></ol><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>架构选型四问：多步推理？依赖关系？结构已知？质量关键？</li><li>从简单开始：单次调用 → ReAct → 多 Agent，按需演进</li><li>常见错误：过度工程、忽视成本、忽略失败处理、静态思维</li><li>核心原则：先让单 Agent 尽量工作，按需演进</li></ul><hr><p><strong>上一章</strong>: <a href="./04-动态编排与迭代.html">动态编排与迭代</a></p><hr><h2 id="模块总结" tabindex="-1">模块总结 <a class="header-anchor" href="#模块总结" aria-label="Permalink to &quot;模块总结&quot;">​</a></h2><p>多 Agent 架构系列全部完结，共 5 章：</p><table tabindex="0"><thead><tr><th>章节</th><th>主题</th><th>核心洞察</th></tr></thead><tbody><tr><td>1</td><td>何时用多Agent</td><td>广度 vs 深度，验证型子Agent最安全</td></tr><tr><td>2</td><td>指挥官与工人</td><td>Anthropic 的多 Agent 架构实践</td></tr><tr><td>3</td><td>六种Workflow模式</td><td>Chaining/Routing/Sectioning/Voting</td></tr><tr><td>4</td><td>动态编排与迭代</td><td>Orchestrator-Workers/Evaluator-Optimizer</td></tr><tr><td>5</td><td>选型与实践</td><td>从简单开始，按需演进</td></tr></tbody></table><hr><p><a href="/Hermes-Engineering-ai-agent-/">← 返回首页</a> | <a href="/Hermes-Engineering-ai-agent-/05-Skill工程/">下一模块: Skill工程 →</a></p>`,22))])}const f=o(g,[["render",d]]);export{C as __pageData,f as default};
